function eligibleForArchive(policy, matches) {
  // Newest-first sort uses parsed timestamp when available, falls back to mtime.
  // This keeps keep_last_n correct (it would otherwise sort by clone-time and pick arbitrary files).
  matches.sort((a, b) => (b.parsedTs || b.mtimeMs) - (a.parsedTs || a.mtimeMs));
  // Floor: never prune the newest keep_last_n files, regardless of retention_days.
  const floor = policy.keep_last_n != null ? new Set(matches.slice(0, policy.keep_last_n).map(m => m.name)) : new Set();
  if (policy.retention_days != null) {
    const cutoff = NOW - policy.retention_days * DAY_MS;
    return matches.filter(m => {
      if (floor.has(m.name)) return false;
      const effTs = m.parsedTs || m.mtimeMs;   // FIX: prefer parsed timestamp
      return effTs < cutoff;
    });
  }
  // keep_last_n-only policy (no retention_days): everything outside the floor is eligible.
  if (policy.keep_last_n != null) return matches.filter(m => !floor.has(m.name));
  return [];
}

