function listMatches(policy) {
  if (!fs.existsSync(policy.dir)) return [];
  const out = [];
  for (const name of fs.readdirSync(policy.dir)) {
    if (!policy.pattern.test(name)) continue;
    const full = path.join(policy.dir, name);
    let st;
    try { st = fs.statSync(full); } catch { continue; }
    if (!st.isFile()) continue;
    const parsedTs = parseFilenameTimestamp(name);   // ADDED
    if (VERBOSE && parsedTs == null) console.log(`  [parse-fallback] ${name} — using mtime`);   // ADDED
    out.push({ name, full, mtimeMs: st.mtimeMs, parsedTs, size: st.size });   // CHANGED: + parsedTs
  }
  out.sort((a, b) => (b.parsedTs || b.mtimeMs) - (a.parsedTs || a.mtimeMs));   // CHANGED: sort by parsedTs
  return out;
}
